import json

# Load the data
file_path = 'file_storage/functions.query_db:38.json'
with open(file_path, 'r') as f:
    businesses = json.load(f)

# Check WiFi values in the data
wifi_values = []
for business in businesses:
    attributes = business.get('attributes', {})
    if attributes and isinstance(attributes, dict):
        wifi = attributes.get('WiFi')
        if wifi is not None:
            wifi_values.append({
                'business_id': business.get('business_id'),
                'wifi': str(wifi),
                'description': business.get('description', '')[:100]
            })

print('__RESULT__:')
print(json.dumps({
    'wifi_values_sample': wifi_values[:10],
    'total_with_wifi_attr': len(wifi_values)
}))

